import{_ as a,o as e,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const g=JSON.parse('{"title":"新手指南","description":"","frontmatter":{},"headers":[],"relativePath":"guides/beginner.md","filePath":"zh/guides/beginner.md","lastUpdated":1775394001000}'),i={name:"guides/beginner.md"};function d(s,t,o,n,h,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="新手指南" tabindex="-1">新手指南 <a class="header-anchor" href="#新手指南" aria-label="Permalink to &quot;新手指南&quot;">​</a></h1><p>欢迎来到忘却前夜！本指南帮助新玩家快速上手这款 Roguelite 卡牌构筑手游。</p><h2 id="游戏简介" tabindex="-1">游戏简介 <a class="header-anchor" href="#游戏简介" aria-label="Permalink to &quot;游戏简介&quot;">​</a></h2><p>忘却前夜是一款以克苏鲁神话为背景的 Roguelite 卡牌构筑游戏。你将扮演守密人，与唤醒体们组成队伍，通过卡牌战斗探索充满未知的世界。</p><p><strong>开发商</strong>: B.I.A.V. Studio（灵犀互娱旗下）</p><h2 id="开局建议" tabindex="-1">开局建议 <a class="header-anchor" href="#开局建议" aria-label="Permalink to &quot;开局建议&quot;">​</a></h2><h3 id="_1-初始召唤" tabindex="-1">1. 初始召唤 <a class="header-anchor" href="#_1-初始召唤" aria-label="Permalink to &quot;1. 初始召唤&quot;">​</a></h3><ul><li>SSR 概率 <strong>3%</strong>，<strong>30 抽</strong> 保底</li><li>建议对初始赠送的抽卡资源进行 reroll（开荒再抽）</li><li>参考 <a href="./tier-list.html">节奏榜</a> 确定目标唤醒体</li></ul><h3 id="_2-推进主线" tabindex="-1">2. 推进主线 <a class="header-anchor" href="#_2-推进主线" aria-label="Permalink to &quot;2. 推进主线&quot;">​</a></h3><ul><li>优先推进主线剧情解锁游戏功能</li><li>通关 <strong>3-2</strong> 解锁相位对弈（PvP）模式</li><li>主线通关赠送大量资源</li></ul><h3 id="_3-理解卡牌系统" tabindex="-1">3. 理解卡牌系统 <a class="header-anchor" href="#_3-理解卡牌系统" aria-label="Permalink to &quot;3. 理解卡牌系统&quot;">​</a></h3><p>这是游戏的核心，需要理解：</p><ul><li><strong>算力（Arithmetica）</strong> - 每回合 5 点，用于打出卡牌</li><li><strong>狂气（Madness）</strong> - 积满 100 触发免费强力爆发</li><li><strong>银钥</strong> - 积满 1000 发动钥令</li><li><strong>四大界域</strong> - 混沌/深海/血肉/超维，决定战斗风格</li></ul><h3 id="_4-阵容构筑" tabindex="-1">4. 阵容构筑 <a class="header-anchor" href="#_4-阵容构筑" aria-label="Permalink to &quot;4. 阵容构筑&quot;">​</a></h3><ul><li>最多 4 名唤醒体组队</li><li>建议前期围绕一个界域构筑</li><li>混沌界域唤醒体可灵活搭配任意队伍</li></ul><h2 id="资源管理" tabindex="-1">资源管理 <a class="header-anchor" href="#资源管理" aria-label="Permalink to &quot;资源管理&quot;">​</a></h2><ul><li><strong>召唤货币</strong> - 留给限定池的目标唤醒体</li><li><strong>培养资源</strong> - 集中投资 1-2 个核心唤醒体</li><li><strong>卡牌升级</strong> - 优先升级核心输出卡牌</li></ul><h2 id="常见新手误区" tabindex="-1">常见新手误区 <a class="header-anchor" href="#常见新手误区" aria-label="Permalink to &quot;常见新手误区&quot;">​</a></h2><ul><li>❌ 分散培养太多唤醒体</li><li>❌ 在常驻池大量抽卡</li><li>❌ 忽略卡牌升级的重要性</li><li>❌ 不理解界域协同机制</li><li>✅ 集中资源培养核心阵容</li><li>✅ 为限定唤醒体储备货币</li><li>✅ 学习构筑思路和卡牌搭配</li><li>✅ 每日完成所有任务和派遣</li></ul><h2 id="服务器选择" tabindex="-1">服务器选择 <a class="header-anchor" href="#服务器选择" aria-label="Permalink to &quot;服务器选择&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>地区</th><th>发行商</th><th>备注</th></tr></thead><tbody><tr><td><span class="server-badge server-cn">国服</span></td><td>中国大陆</td><td>灵犀互娱</td><td>内容最领先</td></tr><tr><td><span class="server-badge server-global">国际服</span></td><td>全球 (Steam)</td><td>B.I.A.V. Studio</td><td>多语言支持</td></tr><tr><td><span class="server-badge server-jp">日服</span></td><td>日本</td><td>AltPlus Inc.</td><td>数值有较大调整</td></tr><tr><td><span class="server-badge server-tw">台服</span></td><td>台湾</td><td>Sialia Games</td><td>繁体中文</td></tr><tr><td>港澳新马</td><td>东南亚</td><td>Qookka Games</td><td>繁中/英文</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">日服差异</p><p>日服版本的唤醒体/装备数值经过大幅调整，与国服/国际服存在较大差异。本Wiki主要以国服/国际服数据为准，日服差异会特别标注。</p></div>',22)])])}const b=a(i,[["render",d]]);export{g as __pageData,b as default};
